{"content":"import { Header } from "@/components/header";
import { Footer } from "@/components/footer";
import { WhatsAppFloat } from "@/components/whatsapp-float";
import { BlogCard } from "@/components/blog-card";
import content from "@/content/es.json";
import fs from "fs";
import path from "path";

export default function BlogPage() {
  const blogPosts = fs.readdirSync("../content/blog").filter((file) => path.extname(file) === ".md").map((file) => ({
    slug: path.basename(file, ".md"),
    title: content.blog[path.basename(file, ".md")].title,
    date: content.blog[path.basename(file, ".md")].date,
  }));

  return (
    <>
      <Header navItems={["Inicio", "Servicios", "Catálogo", "Sobre", "Preguntas", "Contacto"]} />
      <div className="hero">
        <h1>Blog</h1>
      </div>
      <div>
        {blogPosts.map((post) => (
          <BlogCard key={post.slug} slug={post.slug} title={post.title} date={post.date} />
        ))}
      </div>
      <Footer logo="/images/covers/logo-blanco.svg" businessName="Dayah LitWorks" email="dayahlitworks@gmail.com" whatsapp="595986868241" instagram="@dayah.litworks" />
      <WhatsAppFloat phone="595986868241" />
    </>
  );
}
","path":"/tmp/dayah-client/app/blog/page.tsx"}

{"content":"import { Header } from "@/components/header";
import { Footer } from "@/components/footer";
import { WhatsAppFloat } from "@/components/whatsapp-float";
import fs from "fs";
import path from "path";
import markdown from "markdown";

export default function BlogPostPage({ slug }) {
  const markdownContent = fs.readFileSync(`../content/blog/${slug}.md`, 'utf8');
  const htmlContent = markdown.markdown.toHTML(markdownContent);
  const { title, date } = require(`../content/blog/${slug}.json`);

  return (
    <>
      <Header navItems={["Inicio", "Servicios", "Catálogo", "Sobre", "Preguntas", "Contacto"]} />
      <div className="hero">
        <h1>{title}</h1>
      </div>
      <div>
        <h2>{date}</h2>
        <div dangerouslySetInnerHTML={{ __html: htmlContent }} />
      </div>
      <Footer logo="/images/covers/logo-blanco.svg" businessName="Dayah LitWorks" email="dayahlitworks@gmail.com" whatsapp="595986868241" instagram="@dayah.litworks" />
      <WhatsAppFloat phone="595986868241" />
    </>
  );
}
","path":"/tmp/dayah-client/app/blog/[slug]/page.tsx"}

